protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 renamed the default discriminator property from "Discriminator" to "$type".
        // Preserve "Discriminator" so existing 500K documents and direct SQL queries still work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 stopped embedding the discriminator in the JSON id property.
        // Preserve the old "Product|123" id format so existing documents remain accessible.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // REMOVED: HasIndex(p => p.Sku)
    // EF Core 9 Cosmos provider now throws on HasIndex — Cosmos DB indexing is
    // managed via the container's indexing policy (Azure Portal / Bicep / Terraform).
}

